#include<bits/stdc++.h>
using namespace std;

string a[1001];
int k=0;
bool flag=1;
int main(){
	while(1){
		string b;
		cin>>b;
		if(b=="0"){
			break;
		}flag=1;
		for(int i=0;i<k;i++){
			if(b==a[i]){
				flag=0;
				break;
			}
		}if(flag){
			a[k++]=b;
			cout<<b;
		}

	}
	return 0;
}
